#!/usr/bin/env python3
import asyncio
import json
import math
import os
import random
import signal
import time
import uuid
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Tuple, Any

try:
    import websockets
    from websockets.server import WebSocketServerProtocol
except ImportError:
    raise SystemExit("Please install websockets: pip install websockets")


TICK_RATE = float(os.getenv("TICK_RATE", "20"))
HOST = os.getenv("HOST", "0.0.0.0")
PORT = int(os.getenv("PORT", "8765"))
WORLD_SIZE = float(os.getenv("WORLD_SIZE", "5000"))
MAX_HEALTH = 100
MOVE_SPEED = 300.0
SPAWN_COUNT = 64


def now() -> float:
    return time.time()


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


@dataclass
class Vec2:
    x: float
    y: float

    def to_dict(self) -> Dict[str, float]:
        return {"x": self.x, "y": self.y}


@dataclass
class Player:
    id: str
    name: str
    pos: Vec2
    vel: Vec2 = field(default_factory=lambda: Vec2(0.0, 0.0))
    rot: float = 0.0
    health: int = MAX_HEALTH
    alive: bool = True
    connected: bool = True
    last_input_at: float = field(default_factory=now)
    kills: int = 0
    team: Optional[str] = None

    def to_public_state(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "pos": self.pos.to_dict(),
            "vel": self.vel.to_dict(),
            "rot": self.rot,
            "health": self.health,
            "alive": self.alive,
            "connected": self.connected,
            "kills": self.kills,
            "team": self.team,
        }


@dataclass
class Projectile:
    id: str
    owner_id: str
    pos: Vec2
    vel: Vec2
    damage: int
    born_at: float
    ttl: float = 2.0

    def to_state(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "owner_id": self.owner_id,
            "pos": self.pos.to_dict(),
            "vel": self.vel.to_dict(),
            "damage": self.damage,
            "born_at": self.born_at,
            "ttl": self.ttl,
        }


class GameServer:
    def __init__(self) -> None:
        self.clients: Dict[WebSocketServerProtocol, str] = {}
        self.players: Dict[str, Player] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.spawn_points: List[Vec2] = [
            Vec2(random.uniform(0, WORLD_SIZE), random.uniform(0, WORLD_SIZE))
            for _ in range(SPAWN_COUNT)
        ]
        self.running = True
        self.last_tick = now()

    def random_spawn(self) -> Vec2:
        p = random.choice(self.spawn_points)
        return Vec2(p.x + random.uniform(-50, 50), p.y + random.uniform(-50, 50))

    async def register(self, ws: WebSocketServerProtocol) -> str:
        player_id = str(uuid.uuid4())
        player = Player(
            id=player_id,
            name=f"Player-{player_id[:8]}",
            pos=self.random_spawn(),
        )
        self.players[player_id] = player
        self.clients[ws] = player_id
        await self.send(
            ws,
            {
                "type": "welcome",
                "player_id": player_id,
                "tick_rate": TICK_RATE,
                "world_size": WORLD_SIZE,
            },
        )
        return player_id

    async def unregister(self, ws: WebSocketServerProtocol) -> None:
        player_id = self.clients.pop(ws, None)
        if player_id and player_id in self.players:
            self.players[player_id].connected = False

    async def send(self, ws: WebSocketServerProtocol, payload: Dict[str, Any]) -> None:
        try:
            await ws.send(json.dumps(payload, separators=(",", ":")))
        except Exception:
            pass

    async def broadcast(self, payload: Dict[str, Any]) -> None:
        if not self.clients:
            return
        message = json.dumps(payload, separators=(",", ":"))
        dead = []
        for ws in list(self.clients.keys()):
            try:
                await ws.send(message)
            except Exception:
                dead.append(ws)
        for ws in dead:
            await self.unregister(ws)

    async def handle_message(self, ws: WebSocketServerProtocol, raw: str) -> None:
        player_id = self.clients.get(ws)
        if not player_id:
            return
        player = self.players.get(player_id)
        if not player:
            return
        try:
            msg = json.loads(raw)
        except Exception:
            return

        mtype = msg.get("type")
        if mtype == "hello":
            name = str(msg.get("name", "")).strip()
            if name:
                player.name = name[:24]
            team = msg.get("team")
            if isinstance(team, str):
                player.team = team[:24]
        elif mtype == "input":
            move = msg.get("move", {})
            mx = float(move.get("x", 0.0))
            my = float(move.get("y", 0.0))
            mag = math.hypot(mx, my)
            if mag > 1.0:
                mx /= mag
                my /= mag
            player.vel = Vec2(mx * MOVE_SPEED, my * MOVE_SPEED)
            player.rot = float(msg.get("rot", player.rot))
            player.last_input_at = now()
        elif mtype == "shoot" and player.alive:
            angle = float(msg.get("rot", player.rot))
            speed = 1200.0
            proj = Projectile(
                id=str(uuid.uuid4()),
                owner_id=player.id,
                pos=Vec2(player.pos.x, player.pos.y),
                vel=Vec2(math.cos(angle) * speed, math.sin(angle) * speed),
                damage=25,
                born_at=now(),
                ttl=2.0,
            )
            self.projectiles[proj.id] = proj
        elif mtype == "respawn":
            player.pos = self.random_spawn()
            player.health = MAX_HEALTH
            player.alive = True
            player.vel = Vec2(0.0, 0.0)

    def update_players(self, dt: float) -> None:
        for p in self.players.values():
            if not p.connected or not p.alive:
                continue
            p.pos.x = clamp(p.pos.x + p.vel.x * dt, 0.0, WORLD_SIZE)
            p.pos.y = clamp(p.pos.y + p.vel.y * dt, 0.0, WORLD_SIZE)

    def update_projectiles(self, dt: float) -> None:
        t = now()
        remove_ids = []
        for proj in self.projectiles.values():
            proj.pos.x += proj.vel.x * dt
            proj.pos.y += proj.vel.y * dt
            if (
                proj.pos.x < 0
                or proj.pos.y < 0
                or proj.pos.x > WORLD_SIZE
                or proj.pos.y > WORLD_SIZE
                or t - proj.born_at > proj.ttl
            ):
                remove_ids.append(proj.id)
                continue

            for p in self.players.values():
                if not p.alive or not p.connected or p.id == proj.owner_id:
                    continue
                dx = p.pos.x - proj.pos.x
                dy = p.pos.y - proj.pos.y
                if dx * dx + dy * dy <= 30 * 30:
                    p.health -= proj.damage
                    if p.health <= 0:
                        p.health = 0
                        p.alive = False
                        owner = self.players.get(proj.owner_id)
                        if owner:
                            owner.kills += 1
                    remove_ids.append(proj.id)
                    break

        for pid in remove_ids:
            self.projectiles.pop(pid, None)

    def build_full_state(self) -> Dict[str, Any]:
        return {
            "type": "state",
            "server_time": now(),
            "world_size": WORLD_SIZE,
            "players": [p.to_public_state() for p in self.players.values()],
            "projectiles": [proj.to_state() for proj in self.projectiles.values()],
        }

    async def game_loop(self) -> None:
        tick_interval = 1.0 / TICK_RATE
        self.last_tick = now()
        while self.running:
            start = now()
            dt = start - self.last_tick
            self.last_tick = start

            self.update_players(dt)
            self.update_projectiles(dt)

            await self.broadcast(self.build_full_state())

            elapsed = now() - start
            await asyncio.sleep(max(0.0, tick_interval - elapsed))

    async def ws_handler(self, ws: WebSocketServerProtocol) -> None:
        await self.register(ws)
        try:
            async for message in ws:
                await self.handle_message(ws, message)
        finally:
            await self.unregister(ws)

    async def run(self) -> None:
        async with websockets.serve(
            self.ws_handler,
            HOST,
            PORT,
            max_size=2**20,
            ping_interval=20,
            ping_timeout=20,
        ):
            await self.game_loop()


async def main() -> None:
    server = GameServer()
    loop = asyncio.get_running_loop()

    def stop() -> None:
        server.running = False

    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            loop.add_signal_handler(sig, stop)
        except NotImplementedError:
            pass

    await server.run()


if __name__ == "__main__":
    asyncio.run(main())